// Filter Medications by Current Time Slot
// Determines if it's morning (8AM), afternoon (1PM) or night (8PM)
// and returns only medications scheduled for this slot

const allRows = $input.all();
const now = new Date();
const hour = now.getHours();

// Determine current time slot
let currentSlot = '';
if (hour >= 6 && hour < 12)  currentSlot = 'morning';
else if (hour >= 12 && hour < 17) currentSlot = 'afternoon';
else currentSlot = 'night';

const slotLabel = { morning: '🌅 Morning', afternoon: '☀️ Afternoon', night: '🌙 Night' }[currentSlot];

// Filter active medications for this time slot
const dueMeds = allRows.filter(r => {
  const status = (r.json.status || '').toLowerCase();
  const frequency = (r.json.frequency || '').toLowerCase();
  const timeSlots = (r.json.timeSlots || '').toLowerCase();

  if (status !== 'active') return false;

  // Check if this medication is due in current slot
  if (timeSlots.includes(currentSlot)) return true;
  if (frequency === 'once daily' && currentSlot === 'morning') return true;
  if (frequency === 'twice daily' && (currentSlot === 'morning' || currentSlot === 'night')) return true;
  if (frequency === 'thrice daily') return true;
  return false;
});

if (dueMeds.length === 0) {
  return [{ json: { message: `No medications due for ${currentSlot} slot`, count: 0 } }];
}

// Group by patient phone — one message per patient with all their meds
const byPhone = {};
for (const row of dueMeds) {
  const phone = row.json.phone;
  if (!byPhone[phone]) {
    byPhone[phone] = {
      phone,
      patientName: row.json.patientName,
      caregiverPhone: row.json.caregiverPhone,
      medications: [],
      currentSlot,
      slotLabel
    };
  }
  byPhone[phone].medications.push({
    medName: row.json.medName,
    dosage: row.json.dosage,
    instructions: row.json.instructions || '',
    medId: row.json.medId || row.json.medName
  });
}

return Object.values(byPhone).map(p => ({ json: p }));

// Build Medication Reminder Message
// Creates a WhatsApp reminder listing all meds due for this slot

const data = $json;
const { phone, patientName, medications, slotLabel, currentSlot } = data;
const now = new Date();
const logKey = `${phone}_${now.toISOString().split('T')[0]}_${currentSlot}`;

const medLines = medications.map((m, i) =>
  `  ${i + 1}. 💊 *${m.medName}* — ${m.dosage}${m.instructions ? `\n     📝 ${m.instructions}` : ''}`
).join('\n');

const lines = [
  `${slotLabel} *Medication Reminder* 💊`,
  `👋 Hi *${patientName}!*`,
  '',
  `Please take your ${currentSlot} medications:`,
  '',
  medLines,
  '',
  '━━━━━━━━━━━━━━━━━━',
  'Reply with:',
  '✅ *taken* – I have taken my medication',
  '😴 *snooze* – Remind me in 30 minutes',
  '⏭️ *skip* – I am skipping this dose',
];

return {
  json: {
    phone,
    patientName,
    caregiverPhone: data.caregiverPhone,
    currentSlot,
    logKey,
    reminderMessage: lines.join('\n'),
    sentAt: now.toISOString()
  }
};

// Process Taken Response
// Finds the latest Pending log for this patient
// Calculates streak and builds positive reinforcement message

const phone = $('Wati Trigger').first().json.waId|| $('WATI Trigger').item.json.from;
const patientName =  $('Wati Trigger').first().json.senderName|| 'Patient';
const allRows = $input.all();
const now = new Date();
const today = now.toISOString().split('T')[0];

// Find latest pending log for this phone
const myLogs = allRows
  .filter(r => r.json.phone === phone)
  .sort((a, b) => new Date(b.json.sentAt) - new Date(a.json.sentAt));

const pendingLog = myLogs.find(r => r.json.status === 'Pending');

// Calculate current streak (consecutive taken days)
const takenDays = new Set(
  allRows
    .filter(r => r.json.phone === phone && r.json.status === 'Taken')
    .map(r => r.json.date)
);

let streak = 0;
const checkDate = new Date(today);
while (takenDays.has(checkDate.toISOString().split('T')[0])) {
  streak++;
  checkDate.setDate(checkDate.getDate() - 1);
}

// Streak emoji
let streakMsg = '';
if (streak >= 30) streakMsg = `🏆 Incredible! ${streak}-day streak!`;
else if (streak >= 14) streakMsg = `🌟 Amazing! ${streak}-day streak!`;
else if (streak >= 7)  streakMsg = `🔥 On fire! ${streak}-day streak!`;
else if (streak >= 3)  streakMsg = `💪 ${streak}-day streak! Keep going!`;
else streakMsg = `✅ Great job taking your medication!`;

const lines = [
  `✅ *Dose Logged – Taken!*`,
  '',
  `Well done, *${patientName}!* 🎉`,
  streakMsg,
  '',
  `📅 *Date:* ${today}`,
  `🕐 *Time:* ${now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}`,
  '',
  'Consistency is the key to good health! 💚',
  'Reply *mystats* to see your full adherence report.'
];

return [{ json: {
  phone,
  patientName,
  logKey: pendingLog?.json.logKey || `${phone}_${today}_unknown`,
  takenMessage: lines.join('\n'),
  today,
  respondedAt: now.toISOString()
}}];

// Process Skip Response
// Logs the skip, checks for consecutive skips
// If 2+ consecutive skips → flag for caregiver alert

const phone = $('Wati Trigger').first().json.waId || $('WATI Trigger').item.json.from;
const patientName = $input.first().json.patientName || 'Patient';
const allRows = $input.all();
const now = new Date();
const today = now.toISOString().split('T')[0];

const myLogs = allRows
  .filter(r => r.json.phone === phone)
  .sort((a, b) => new Date(b.json.sentAt) - new Date(a.json.sentAt));

const pendingLog = myLogs.find(r => r.json.status === 'Pending');
caregiverPhone = $input.first().json.caregiverPhone || '';

// Count consecutive recent skips
const recentLogs = myLogs.slice(0, 6);
const consecutiveSkips = recentLogs.filter(r => r.json.status === 'Skipped').length;
const alertCaregiver = consecutiveSkips >= 2;

const skipLines = [
  `⏭️ *Dose Logged – Skipped*`,
  '',
  `We've noted your skip, *${patientName}.*`,
  '',
  '⚠️ Please consult your doctor before skipping medication regularly.',
  '💡 Tip: If you are experiencing side effects, contact your healthcare provider.',
  '',
  'Your next reminder will be sent on schedule.',
  'Reply *mystats* to see your adherence report.'
];

const caregiverLines = alertCaregiver ? [
  `🚨 *Medication Skip Alert*`,
  '',
  `👤 *Patient:* ${patientName}`,
  `📞 *Phone:* ${phone}`,
  `⏭️ *Consecutive Skips Detected:* ${consecutiveSkips + 1}`,
  `📅 *Date:* ${today}`,
  `🕐 *Time:* ${now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}`,
  '',
  'Please check in with the patient.'
] : [];

return [{ json: {
  phone,
  patientName,
  caregiverPhone,
  logKey: $input.first().json.logKey || `${phone}_${today}_unknown`,
  skipMessage: skipLines.join('\n'),
  caregiverMessage: caregiverLines.join('\n'),
  alertCaregiver,
  respondedAt: now.toISOString()
}}];

// Process Snooze Request
// Logs snooze with a follow-up time 30 minutes from now

const phone = $json.waId || $json.from || 'unknown';
const patientName = $json.senderName || 'Patient';
const now = new Date();
const followUpTime = new Date(now.getTime() + 30 * 60 * 1000);

const snoozeLines = [
  `😴 *Snooze Set!*`,
  '',
  `No problem, *${patientName}!*`,
  `We'll remind you again at *${followUpTime.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}*. ⏰`,
  '',
  '💊 Please don\'t forget your medication!'
];

return [{ json: {
  phone,
  patientName,
  snoozeMessage: snoozeLines.join('\n'),
  followUpAt: followUpTime.toISOString(),
  snoozedAt: now.toISOString()
}}];

// Check Snooze Queue & Missed Doses
// 1. Finds snooze entries where followUpAt <= now → resend reminder
// 2. Finds AdherenceLog entries that are still Pending after 2 hours → missed dose

const allSnooze = $input.all();
const now = new Date();

// Filter snooze entries due for follow-up
const dueSnoozes = allSnooze.filter(r => {
  const followUpAt = new Date(r.json.followUpAt);
  return r.json.status === 'Pending' && followUpAt <= now;
});

if (dueSnoozes.length === 0) {
  return [{ json: { message: 'No snooze follow-ups due', count: 0, items: [] } }];
}

return dueSnoozes.map(r => ({
  json: {
    phone: r.json.phone,
    patientName: r.json.patientName,
    followUpMessage: `⏰ *Snooze Reminder!*\n\n💊 Hi *${r.json.patientName}!* It\'s time to take your medication now.\n\nReply *taken*, *skip* or *snooze* to log your response.`
  }
}));

// Detect Missed Doses
// Finds AdherenceLog entries still 'Pending' after 2 hours
// Groups by caregiver phone and builds alert messages

const allRows = $input.all();
const now = new Date();
const twoHoursAgo = new Date(now.getTime() - 2 * 60 * 60 * 1000);

const missedItems = allRows.filter(r => {
  const sentAt = new Date(r.json.sentAt || 0);
  return r.json.status === 'Pending' && sentAt <= twoHoursAgo;
});

if (missedItems.length === 0) {
  return [{ json: { message: 'No missed doses detected', count: 0 } }];
}

// Group by caregiver so one message per caregiver
const byCg = {};
for (const row of missedItems) {
  const cg = row.json.caregiverPhone;
  if (!cg) continue;
  if (!byCg[cg]) byCg[cg] = [];
  byCg[cg].push(row.json);
}

return Object.entries(byCg).map(([cgPhone, items]) => {
  const lines = [
    `🚨 *Missed Dose Alert*`,
    '',
    `The following patient(s) have NOT responded to their medication reminder:`,
    ''
  ];
  for (const item of items) {
    lines.push(`👤 *${item.patientName}* (${item.phone})`);
    lines.push(`   📅 Date: ${item.date} | Slot: ${item.slot}`);
    lines.push(`   ⏰ Reminder sent at: ${new Date(item.sentAt).toLocaleTimeString('en-IN', {hour:'2-digit',minute:'2-digit'})}`);
    lines.push('');
  }
  lines.push('Please follow up with the patient immediately.');
  return { json: { caregiverPhone: cgPhone, alertMessage: lines.join('\n') } };
});

// Build My Stats Report
// 7-day adherence %, streak, best day, visual bar chart

const phone = $('Wati Trigger').first().json.waId || $('WATI Trigger').item.json.from;
const patientName = $('Wati Trigger').first().json.senderName || 'Patient';
const allRows = $input.all();
const now = new Date();

const myLogs = allRows.filter(r => r.json.phone === phone);

if (myLogs.length === 0) {
  return [{ json: { phone, statsMessage: `📊 No medication history found yet, *${patientName}!*\n\nStart taking your medications and reply *taken* after each dose.` } }];
}

// Last 7 days analysis
const last7 = [];
for (let i = 6; i >= 0; i--) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const dateStr = d.toISOString().split('T')[0];
  const dayLogs = myLogs.filter(r => r.json.date === dateStr);
  const taken  = dayLogs.filter(r => r.json.status === 'Taken').length;
  const total  = dayLogs.filter(r => r.json.status !== 'Pending').length;
  const pct    = total > 0 ? Math.round((taken / total) * 100) : null;
  last7.push({ dateStr, taken, total, pct, dayName: d.toLocaleDateString('en-IN', { weekday: 'short' }) });
}

const totalTaken   = myLogs.filter(r => r.json.status === 'Taken').length;
const totalLogged  = myLogs.filter(r => r.json.status !== 'Pending').length;
const overallPct   = totalLogged > 0 ? Math.round((totalTaken / totalLogged) * 100) : 0;

// Current streak
let streak = 0;
const sortedDates = [...new Set(myLogs.filter(r=>r.json.status==='Taken').map(r=>r.json.date))].sort().reverse();
const checkDate = new Date(now);
for (const d of sortedDates) {
  if (d === checkDate.toISOString().split('T')[0]) {
    streak++;
    checkDate.setDate(checkDate.getDate() - 1);
  } else break;
}

// Bar chart for last 7 days
const barLines = last7.map(d => {
  if (d.pct === null) return `${d.dayName}: ─── No data`;
  const filled = Math.round(d.pct / 10);
  const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);
  const emoji = d.pct === 100 ? '✅' : d.pct >= 50 ? '⚠️' : '❌';
  return `${d.dayName} ${bar} ${d.pct}% ${emoji}`;
});

// Overall bar
const overallFilled = Math.round(overallPct / 10);
const overallBar = '█'.repeat(overallFilled) + '░'.repeat(10 - overallFilled);

const lines = [
  `📊 *Medication Adherence Report*`,
  `👤 *${patientName}*`,
  '',
  `${overallBar} *${overallPct}% Overall*`,
  `🔥 *Current Streak:* ${streak} day${streak !== 1 ? 's' : ''}`,
  '',
  '━━ *Last 7 Days* ━━',
  ...barLines,
  '',
  `✅ Taken: ${totalTaken} doses`,
  `⏭️ Skipped: ${myLogs.filter(r=>r.json.status==='Skipped').length} doses`,
  `❓ Missed: ${myLogs.filter(r=>r.json.status==='Pending').length} doses`,
  '',
  'Keep it up! Consistency saves lives 💚'
];

return [{ json: { phone, statsMessage: lines.join('\n') } }];

// Build My Medications Schedule
// Shows today's full schedule with timings and dosage

const phone = $('Wati Trigger').first().json.waId|| $('WATI Trigger').item.json.from;
const patientName =$('Wati Trigger').first().json.senderName|| 'Patient';
const allRows = $input.all();

const myMeds = allRows.filter(r =>
  r.json.phone === phone && (r.json.status || '').toLowerCase() === 'active'
);

if (myMeds.length === 0) {
  return [{ json: { phone, myMedsMessage: `💊 No active medications found, *${patientName}.*\n\nPlease contact your healthcare provider.` } }];
}

const slotMap = { morning: '🌅 Morning (8:00 AM)', afternoon: '☀️ Afternoon (1:00 PM)', night: '🌙 Night (8:00 PM)' };
const grouped = { morning: [], afternoon: [], night: [] };

for (const row of myMeds) {
  const slots = (row.json.timeSlots || 'morning').split(',').map(s => s.trim().toLowerCase());
  for (const slot of slots) {
    if (grouped[slot]) grouped[slot].push(row.json);
  }
}

const today = new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const lines = [
  `💊 *Today's Medication Schedule*`,
  `👤 *${patientName}*`,
  `📅 ${today}`,
  ''
];

for (const [slot, meds] of Object.entries(grouped)) {
  if (meds.length === 0) continue;
  lines.push(slotMap[slot]);
  for (const m of meds) {
    lines.push(`  • *${m.medName}* — ${m.dosage}`);
    if (m.instructions) lines.push(`    📝 ${m.instructions}`);
  }
  lines.push('');
}

lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('Reply *taken*, *skip* or *snooze* after each dose.');
lines.push('Reply *mystats* for your adherence report.');

return [{ json: { phone, myMedsMessage: lines.join('\n') } }];

// Build Caregiver Patient Report
// Caregiver sends: 'report 919876543210'
// Returns full adherence summary for that patient

const text = $('Wati Trigger').first().json.text||''.trim();
const caregiverPhone =  $input.first().json.caregiverPhone|| $('WATI Trigger').item.json.from;
const patientPhone = $('Wati Trigger').first().json.waId;

if (!patientPhone) {
  return [{ json: { phone: caregiverPhone, reportMessage: '⚠️ Please provide a patient phone number.\nExample: *report 919876543210*' } }];
}

const allRows = $input.all();
const patientLogs = allRows.filter(r => r.json.phone === patientPhone);

if (patientLogs.length === 0) {
  return [{ json: { phone: caregiverPhone, reportMessage: `❌ No records found for *${patientPhone}*.` } }];
}

const patientName = patientLogs[0].json.patientName || 'Patient';
const totalTaken   = patientLogs.filter(r => r.json.status === 'Taken').length;
const totalSkipped = patientLogs.filter(r => r.json.status === 'Skipped').length;
const totalMissed  = patientLogs.filter(r => r.json.status === 'Pending').length;
const totalLogged  = totalTaken + totalSkipped + totalMissed;
const adherencePct = totalLogged > 0 ? Math.round((totalTaken / totalLogged) * 100) : 0;

// Last 7 days summary
const now = new Date();
const recentDays = [];
for (let i = 6; i >= 0; i--) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const dateStr = d.toISOString().split('T')[0];
  const dayLogs = patientLogs.filter(r => r.json.date === dateStr);
  const t = dayLogs.filter(r => r.json.status === 'Taken').length;
  const tot = dayLogs.filter(r => r.json.status !== 'Pending').length;
  const pct = tot > 0 ? Math.round((t / tot) * 100) : null;
  const dayName = d.toLocaleDateString('en-IN', { weekday: 'short', month: 'short', day: 'numeric' });
  const emoji = pct === null ? '─' : pct === 100 ? '✅' : pct >= 50 ? '⚠️' : '❌';
  recentDays.push(`${dayName}: ${pct !== null ? pct + '%' : 'No data'} ${emoji}`);
}

const overallFilled = Math.round(adherencePct / 10);
const overallBar = '█'.repeat(overallFilled) + '░'.repeat(10 - overallFilled);

const lines = [
  `📋 *Patient Adherence Report*`,
  `👤 *Patient:* ${patientName}`,
  `📞 *Phone:* ${patientPhone}`,
  '',
  `${overallBar} *${adherencePct}% Overall*`,
  '',
  `✅ *Taken:* ${totalTaken} doses`,
  `⏭️ *Skipped:* ${totalSkipped} doses`,
  `❓ *Missed:* ${totalMissed} doses`,
  `📦 *Total Logged:* ${totalLogged} doses`,
  '',
  '━━ *Last 7 Days* ━━',
  ...recentDays,
  '',
  `Report generated: ${now.toLocaleDateString('en-IN')}`
];

return [{ json: { phone: caregiverPhone, reportMessage: lines.join('\n') } }];
